UPDATE tb_role
SET role_nm = #{role_nm}, description = #{description}, use_yn = #{use_yn}
WHERE role_cd = #{role_cd}

UPDATE tb_menu
SET menu_nm = #{menu_nm}, parent_id = #{parent_id}, menu_type = #{menu_type},
    pgm_id = #{pgm_id}, url = #{url}, icon = #{icon}, sort_order = #{sort_order}, use_yn = #{use_yn}
WHERE menu_id = #{menu_id}

UPDATE tb_pgm_info
SET pgm_nm=#{pgm_nm}, srch_yn=#{srch_yn}, new_yn=#{new_yn}, save_yn=#{save_yn}, del_yn=#{del_yn},
    prnt_yn=#{prnt_yn}, upld_yn=#{upld_yn}, init_yn=#{init_yn},
    etc_desc1=#{etc_desc1}, etc_desc2=#{etc_desc2}, etc_desc3=#{etc_desc3}, etc_desc4=#{etc_desc4}, etc_desc5=#{etc_desc5}
WHERE pgm_id = #{pgm_id}
